var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"크리스마스 당일\\n사건 발생 <color=#ffd34c>10분 전</color>","JPN":"クリスマス当日\\n事件発生<color=#ffd34c>10分前</color>","ENG":"Christmas Day\\n<color=#ffd34c>10 minutes before</color> the incident","TWN":"聖誕節當天\\n事件發生 <color=#ffd34c>10分鐘前</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제5본당","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第5本堂","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council's 5th Parish","TWN":"<color=#ffd34c>聖皇廳</color> 奇蹟議會第五主堂"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"좋아, 아무래도 내가 가장 먼저 도착한 것 같네.","JPN":"よし、どうやら私が一番乗りみたいだね。","ENG":"Okay. It seems that I'm the first to arrive.","TWN":"看來我是第一個到的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다행히 아직 성탄제는 시작하지 않았어.","JPN":"幸いまだ聖誕祭は始まっていない。","ENG":"Luckily, the party hasn't started yet.","TWN":"幸好聖誕節宴會還沒開始。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래, 지금이라도 넬슨 수녀님께 양해를 구하고 사실대로 말하는 거야……!","JPN":"そうだよ、今からでもシスターネルソンに謝って本当のことを話すんだ……！","ENG":"Yeah, I should go tell Nelson the truth and ask for forgiveness...!","TWN":"對，現在就去向尼爾森修女道歉，把事實告訴她……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그게 아니라면…….","JPN":"それとも……","ENG":"Or…","TWN":"或者說……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"적어도 침식체가 부화하기 전에 솔로카오 초콜릿으로 만든 디저트를 파괴해야만 해……!","JPN":"侵食体が孵化する前に、ソロカオチョコレートで作ったデザートを破壊しないと……！","ENG":"I must destroy the dessert made with Solocao chocolate before a C.O. hatches from it...!","TWN":"至少在侵蝕體孵化之前，必須摧毀那個用獨株巧克力製作的甜點……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"서두르자! 누가 보기 전에 얼른 해치우는 거야……!","JPN":"急ごう！　誰かに見られる前にさっさと片付けるんだ……！","ENG":"I got to hurry! Before anyone else sees...!","TWN":"快點！在被人看到之前趕緊解決掉……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으음……?","JPN":"あれ……？","ENG":"Hmm…?","TWN":"嗯……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"히, 히이이익……!?","JPN":"ひ、ひいいいっ……！？","ENG":"Eeeek...?!","TWN":"咿、咿咿咿……？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 나이프들은 다 뭐야? 갑자기 어디서 날아온 건데!?","JPN":"このナイフはなんだ？　いきなりどこから飛んできた！？","ENG":"Where did all these knives suddenly come from?!","TWN":"這些飛刀是怎麼回事？突然從哪裡飛來的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_QM","text":{"KOREA":"걱정하지 마세요. 방금 건 일부로 빗맞혔으니까요.","JPN":"心配しないでください。今のはわざと外しました。","ENG":"Not to worry. I purposely missed this time.","TWN":"不用擔心，剛才那一擊是故意打偏的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다, 당신은……?","JPN":"あ、あなたは……？","ENG":"Y-you're...?","TWN":"你是……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 무슨 변명을 늘어놓을지 궁금했거든요, 론 리 교수.","JPN":"あなたがどんな言い訳をするか、気になっていましたわ。ローン・リー教授。","ENG":"I am curious to what kind of excuse you will make, Professor Lone Lee.","TWN":"我很好奇你會找什麼藉口，隆利教授。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 지금은 관리국 지명수배자라고 해야 할까요?","JPN":"いいえ、今は管理局の指名手配犯と言うべきでしょうか？","ENG":"Or rather, would you like me to call you the Administration's wanted criminal?","TWN":"喔不，現在該叫你管理局通緝犯才對吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"엘리자베스 팬드래건? 당신이 왜 여기에……?","JPN":"エリザベス・ペンドラゴン？　どうしてあなたがここに……？","ENG":"Elizabeth Pendragon? What are you doing here...?","TWN":"伊莉莎白·潘德拉貢？你為什麼會在這裡……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 여기에? 어리석은 질문이네요.","JPN":"どうしてここに？　愚かな質問ですわね。","ENG":"What am I doing here? What a foolish question.","TWN":"為什麼在這裡？真是個愚蠢的問題。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"명심해두세요. 모든 사람들은 저마다의 격을 가지기 마련이죠.","JPN":"肝に銘じておきなさい。すべての人はそれぞれの格を持っているのです。","ENG":"Keep in mind, everyone has their own level of dignity to uphold.","TWN":"請記住，每個人都有屬於自己的格調。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 저같이 고귀한 품격을 가진 인물은 서있는 곳 자체가 그에 걸맞은 의미를 가지게 된답니다.","JPN":"ですが、私のような高貴な品格を持っている人物は、立っている場所自体がそれ相応の意味を持つのですわ。","ENG":"But for a person of noble character like me being here has its own meaning.","TWN":"但是像我這樣擁有高貴品格的人，所站的地方本身就會賦予其相符的意義。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"걸맞은 의미? 무슨 뚱딴지 같은 소리야?","JPN":"それ相応の意味？　何バカげたこと言ってるんだ？","ENG":"Its own meaning? What are you talking about?","TWN":"相符的意義？你在胡說什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그… 아가씨께서는 심의회의 초청을 받고 여기에 오셨다는 뜻입니다.","JPN":"その……お嬢様は審議会から招待されてここに来たという意味です。","ENG":"Well... Lady Elizabeth is here after receiving an invitation from the Investigation Council.","TWN":"意思是小姐是受議會的邀請來到這裡的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아… 네에…….","JPN":"あ……はあ……","ENG":"Oh... Okay...","TWN":"啊……是……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 저는 당신이 이곳에 있는 게 이상하군요.","JPN":"それより、あなたがここにいるのがおかしいですね。","ENG":"What's odd is that you are here.","TWN":"比起這個，我覺得你在這裡很奇怪。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 첩보에 따르면, 발렌타인 사태를 벌인 당신은 관리국의 형무소를 탈옥 후…….","JPN":"機関の諜報によりますと、バレンタイン事態を起こしたあなたは管理局の刑務所から脱獄し……","ENG":"According to the Institution's intel, after you caused that vile Valentine’s Day incident, you escaped the Administration's prison and...","TWN":"根據機構的情報，製造了情人節事件的你從管理局的監獄越獄後……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"추적을 피해, 프론트베이 남쪽 섬에 머물고 있다고 들었는데요?","JPN":"追跡を避けて、フロントベイの南にある島にいると聞きましたが？","ENG":"I heard you were somewhere in the southern islands of Front Bay to avoid being pursued.","TWN":"為了躲避追蹤，藏在前灣南部的島上？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모두가 행복해야 할 크리스마스에 삼류 악당이 무슨 용건으로 여기에 나타난 거죠?","JPN":"皆が幸せであるべきクリスマスに三流の悪党が何の用でここにいるのですか？","ENG":"So, what business does a third-rate criminal like yourself have showing up here on Christmas, when everyone should be happy?","TWN":"在這個快樂的聖誕節，你這個三流惡棍為什麼要來這裡呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사, 삼류 악당이라니…! 말이 심하잖아……!","JPN":"さ、三流の悪党って……！　ひどい……！","ENG":"Th-third-rate criminal...?! You're crossing the line right there...!","TWN":"三、三流惡棍……！你這話也太過分了吧……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"나도 여기 온 건 나름대로 사정이 있다고!","JPN":"私がここに来たのは、私なりの事情がある！","ENG":"I also have a reason for being here too, you know!","TWN":"我來這裡也是有我的理由的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사정? 그 사정이라는 건, 누가 보기전에 누군가를 해치우는 것과 관련된 것인가요?","JPN":"事情？　その事情というものは、誰かに見られる前に誰かを片付けることと関係があるのですか？","ENG":"A reason? Does that reason involve killing someone before anyone notices?","TWN":"理由？你說的理由，是指在別人看到之前解決掉某個人的事情嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"누군가를 해치운다고……?","JPN":"誰かを片付けるって……？","ENG":"Killing someone...?","TWN":"要解決掉某個人……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐! 왜 멋대로 오해하고 난리야!","JPN":"ま、待ってよ！　何を勝手に誤解してるんだ！","ENG":"W-wait! Why are you jumping to conclusions like that?!","TWN":"等、等一下！你不要妄自揣測！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"대체 언제부터 엿듣고 있던 건데!? 내가 해치우려고 했던 건 사람이 아니라고……!","JPN":"いったいいつから盗み聞きしてたんだよ！？　私が片付けようとしたのは人じゃない……！","ENG":"How much did you overhear?! What I'm going to destroy isn't a person...!","TWN":"你到底從什麼時候開始偷聽的？！我想要幹掉的可不是人類啊……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"디저트란 말이야!","JPN":"デザートだ！","ENG":"It's a dessert!","TWN":"我說的是甜點！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흐음, 그렇군요. 디저트를 해치운다라…….","JPN":"ふーん、そうですか。デザートを片付ける……","ENG":"Hmm, I see. Destroying a dessert, you say...","TWN":"嗯，這樣啊，消滅甜點嗎……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"흐, 흐갸아악!! 무슨 짓이야!!","JPN":"ひ､ひいいいっ！！　何するんだ！！","ENG":"W-whooooa!! What are you doing to me?!","TWN":"呃、呃啊啊啊！！你幹什麼！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 변명을 늘어놓을지 궁금했는데, 삼류 악당 다운 구차한 변명이네요.","JPN":"どんな言い訳をするかと思ったら、三流の悪党らしいくだらない言い訳ですわね。","ENG":"I was wondering what your excuse would be, and it was one befitting of a third-rate criminal.","TWN":"我還在想你會找什麼藉口，這藉口也很三流嘛。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 삼류 답게 얌전히 퇴장하세요.","JPN":"では、三流らしく大人しく退場しなさい。","ENG":"Now, please leave the premises like the third-rate criminal you are.","TWN":"那麼，就像個三流人物一樣乖乖退場吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"히익!?","JPN":"ひいっ！？","ENG":"Eeek!","TWN":"哎呀？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이, 이봐! 그 나이프 내려놓고 잠깐 내 말 좀 들어봐!","JPN":"ちょ、ちょっと！　そのナイフ下ろして、ひとまず私の話を聞け！","ENG":"H-hey! Would you lower that knife and just listen to me?!","TWN":"喂、喂！放下那把刀，聽我說！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"나도 어쨌든 넬슨 수녀님께 정식으로 초대받은 손님이란 말이야!","JPN":"とにかく私もシスター・ネルソンから正式に招待された客なんだって！","ENG":"I also have an invitation from Sister Nelson!","TWN":"我也是受尼爾森姊妹正式邀請的客人啊！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그런 날 공격하면, 당신 입장도 곤란해질 텐데?","JPN":"そんな私を攻撃すると、あなたの立場もまずいことになるだろう？","ENG":"If you attack me, you're gonna be in trouble...!","TWN":"聖誕節這種日子還來打我，你好意思嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성황청의 신실한 심판자들이 관리국 지명수배자인 당신을 초대했다고요?","JPN":"聖皇庁の誠実な審判者が管理局の指名手配犯であるあなたを招待したということですか？","ENG":"The holy adjudicators of Holy Curia invited you, a wanted fugitive of the Administration?","TWN":"聖皇廳忠實的審判者們邀請了你這個管理局通緝犯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"농담이 심하네요. 그걸 지금 저보고 믿으라는 건가요?","JPN":"冗談が過ぎますわ。それを私に信じろとでも？","ENG":"Only a fool would fall for such lies. Did you think I would believe that?","TWN":"玩笑開太過火了吧，你現在要我相信這些嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래, 초대장……!","JPN":"そうだ、招待状……！","ENG":"Okay, the invitation...!","TWN":"對，邀請函……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"초대장 보여주면 될 거 아니야! 거기 딱 기다리라고!","JPN":"招待状を見せればいいんだよな！　ちょっと待ってろよ！","ENG":"I'll show you my invitation! Just give me a second!","TWN":"出示邀請函就行了吧！在那裡等著！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……어디갔지?","JPN":"……あれ、ない？","ENG":"...Where did it go?","TWN":"……去哪裡了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으갸아아악……!!","JPN":"ふんぎゃあああぁっ……！！","ENG":"Waaah...!","TWN":"呃啊啊啊……！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L27_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"음, 이건……?","JPN":"うむ、これは……？","ENG":"Mm? This is...","TWN":"嗯，這是……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨, 이걸 보십시오. 바닥에 떨어져 있었습니다.","JPN":"お嬢様、ご覧ください。床に落ちていました。","ENG":"Take a look at this, my lady. It was on the ground.","TWN":"小姐，請看這個，在地上撿到的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이건… 성황청의 인장이 찍힌 초대장이로군요. 위조된 인장은 아니네요.","JPN":"これは……聖皇庁の印章が押されている招待状ですわね。偽造された印章ではありません。","ENG":"This is... an invitation with Holy Curia's insignia. I do not think it is counterfeit.","TWN":"這是……蓋有聖皇廳印章的邀請函，印章並非偽造。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"수취자 이름은 로널드 리……?","JPN":"受取人はロナルド・リー……？","ENG":"The recipient's name is Ronald Lee...?","TWN":"受邀人名字是隆利……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그, 그거야……!","JPN":"そ、それだ……！","ENG":"Th-that's it...!","TWN":"那、那是……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그거 내 이름이라고…! 이제 됐지?","JPN":"それ、私の名前だよ……！　もういいだろう！","ENG":"That's my name! Happy now?","TWN":"那是我的名字……！現在行了吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"응…? 이건 또 무슨……?","JPN":"うん……？　今度はまた何……？","ENG":"Hmm...? What's going on–","TWN":"嗯……？這又是什麼……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"커허어어어어억……!!","JPN":"ぐはあああああっ……！！","ENG":"WHOOOOOA...!!","TWN":"欸，不對……！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"빨리! 다들 빨리 서둘러!","JPN":"早く！　みんな急げ！","ENG":"Hurry! Everyone, make haste!","TWN":"快點！大家快點，趕緊的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 성탄제인가 뭔가가 시작되기 전에 서둘러 조치를 취해야 해!","JPN":"その聖誕祭とやらが始まる前に早くなんとかしないとダメだ！","ENG":"We must act quickly before the Christmas party or whatever starts!","TWN":"在那什麼聖誕節宴會開始之前，必須趕緊採取措施！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그렇지 않으면 돌이킬 수 없는 사태가 벌어질지도 몰라!","JPN":"さもなければ、取り返しのつかない事態が起きるかもしれない！","ENG":"If not, the situation will be out of our hands!","TWN":"否則可能會發生無法挽回的事態！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으… 다들 미안해…….","JPN":"うう……みんな、ごめん……","ENG":"Ooh... I'm so sorry...","TWN":"嗚嗚……對不起，大家……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"시끄러! 이미 엎질러 진 물이니까, 정신 똑바로 차리기나 해!","JPN":"うるさい！　すでに起きたことだ、しっかりしろ！","ENG":"Shut it! What's done is done, so keep your head in the game!","TWN":"閉嘴！事已至此覆水難收，打起精神來！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우린 지금 관리국 이상으로 성가신 악질 집단에게 전면전을 선포한 거나 다름없다고!","JPN":"妾たちは今、管理局よりやっかいな悪質集団に全面戦争を宣布したようなものだ！","ENG":"Right now, we just declared an all-out war against a vicious group that's even more annoying than the Administration!","TWN":"我們現在等於是向比管理局還要棘手的惡勢力集團宣戰了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아오, 머리야…….","JPN":"うう、頭が……","ENG":"Ugh, my head...","TWN":"啊喔，頭好疼……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"야! 너희들은 또 뭐야! 왜 사람을 밀쳐놓고 미안하다는 소리도…… ","JPN":"おい！　なんだあなたたちは！　人を押しのけて謝らないなんて……","ENG":"Hey! What's your deal?! Aren't you going to apologize after pushing me–","TWN":"喂！你們又是什麼人！為什麼推開別人連句對不起都不說……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으음?","JPN":"ううん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"잠깐, 거기 두 녀석은 노답 삼총사잖아……?","JPN":"待て、そこの2人はあたおか三銃士じゃないか……？","ENG":"Wait, aren't you two part of the idiot trio...?","TWN":"等一下，那兩個傢伙不是笨蛋三劍客嗎……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"엇! 곱슬머리 박사!","JPN":"あっ！　縮れ毛博士！","ENG":"Huh! It's the curly-haired doc!","TWN":"哎呀！卷髮博士！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 아하하… 박사님, 먼저 와 계셨네요…….","JPN":"あ、あはは……博士、もう来てたんですね……","ENG":"A-ah hah hah... I didn't know you'd be here before us...","TWN":"啊，哈哈哈……博士，你已經先到了啊……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"너희들 이게 다 무슨 소동인데? 진짜 싸움이라도 하러 온 거야?","JPN":"あなたたち、これはいったいなんだ？　本当にケンカでもしに来たのか？","ENG":"So, what's all this fuss about? Did you really come here to fight?","TWN":"你們這是在搞什麼鬼？真的是來打架的嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그게 말이죠…….","JPN":"そ、それがですね……","ENG":"W-well...","TWN":"那、那是因為……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당신들, 성탄제에 초대받은 손님들이야?","JPN":"みんな、聖誕祭に招待されたお客さんなのか？","ENG":"Hey, are you even guests invited to the Christmas party?","TWN":"你們是被邀請來參加聖誕節宴會的客人嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"미안하지만, 오늘 성탄제는 취소야. 그러니까 휘말리기 싫으면 어서 돌아가라고.","JPN":"悪いが、今日の聖誕祭はキャンセルだ。そういうことだから巻き込まれたくなかったら早く帰れ。","ENG":"I'm sorry to tell you, but the party is canceled. So, if you don't want to get caught up in this mess, you should turn around.","TWN":"抱歉，今天的宴會取消了。所以如果不想被捲入的話，趕快回去吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"취소라고? 당신이 뭔데 그걸 결정해?","JPN":"キャンセル？　なんであなたがそんなこと決めるんだ？","ENG":"Canceled? Who gave you the right to cancel it?","TWN":"取消？你憑什麼決定？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"스트레가 마녀 협회…….","JPN":"ストレガ魔女協会……","ENG":"The Strega Witch Association...","TWN":"史特雷加魔女協會……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"협회장 라우라 베아트릭스 씨로군요. 첩보 말고 실제로 보는 건 처음이네요.","JPN":"協会長のラウラ・ベアトリクスさんですわね。諜報では聞いていましたが、実際に会うのは初めてです。","ENG":"I see you are Laura Beatrix, the president of the association. This is my first time seeing you in person rather than through intel.","TWN":"是會長蘿拉·貝阿朵莉絲小姐啊。除了情報之外，還是第一次見到她本人呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"첩보? 어디서 뭘 주워들었는지 모르겠는데, 협회장은 공석이라 임시로 맡았을 뿐이야.","JPN":"諜報？　どこで何を聞いたのかはわからないが、協会長が不在で妾は臨時なだけだ。","ENG":"Intel? I don't know what you were told, but the president position is still vacant, and I'm just temporarily in charge.","TWN":"情報？不知道你從哪裡聽來的，會長的職位現在是空缺的，我只是暫時代理而已。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"본업은 그냥 자영업자일 뿐이고.","JPN":"本職はただの商売人である。","ENG":"My main job is managing a business.","TWN":"我的本業只是自營業者。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"보기보다 겸손이 과하네요, 마녀.","JPN":"そのようなご謙遜を。魔女。","ENG":"You are humbler than you seem, witch.","TWN":"沒想到你這麼謙虛呢，魔女。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 프리드웬 기관의 기관장, 엘리자베스 팬드래건이라고 합니다.","JPN":"私はプリドウェン機関の機関長、エリザベス・ペンドラゴンと申します。","ENG":"I am Elizabeth Pendragon, Chief of the Prydwen Institution.","TWN":"我是普利多溫機關的機關長，伊莉莎白·潘德拉貢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"프리드웬이라고…? 하아, 또 귀찮은 녀석들이랑 엮여버렸잖아……?","JPN":"プリドウェンだと……？　はあ、また面倒くさいやつらと関わってしまったか……","ENG":"Prydwen...? Ugh, another annoying group again...?","TWN":"普利多溫嗎……？唉，又被一群煩人的傢伙纏上了……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아니지. 오히려 지금은 전력이 될지도 모르겠네.","JPN":"いや。むしろ今は戦力になるかもしれないな。","ENG":"No. Maybe now, they can actually be of help.","TWN":"不對，現在反而可能成為戰力呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 성탄제가 취소되었다는 게 무슨 뜻이죠?","JPN":"それで、聖誕祭がキャンセルになったというのはどういうことですか？","ENG":"So, what did you mean by the party being canceled?","TWN":"所以聖誕節宴會被取消是什麼意思？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성탄제에 초대받은 손님으로서 자세한 사정을 들을 권리가 있다고 생각합니다만.","JPN":"聖誕祭に招待された客として、詳しい事情を聞く権利があると思いますわ。","ENG":"I believe that those who were invited have a right to know what is going on.","TWN":"作為宴會受邀的客人，我認為我有權了解詳細情況。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아, 어쩔 수 없지…….","JPN":"はあ、仕方ない……","ENG":"*Sigh* Fine...","TWN":"哈啊，沒辦法……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당신네들도 마찬가지겠지만, 얼마 전에 성황청에서 한 수녀님이 찾아왔어.","JPN":"そちらも同じだろうが、少し前に聖皇庁からあるシスターがやってきた。","ENG":"I'm sure she visited you too, but a Sister from Holy Curia recently visited us.","TWN":"你們應該也是一樣吧，前不久有一位修女從聖皇廳找上門來。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"성탄제 때문에 특별한 디저트를 만드는데, 젤라틴이 필요하다 뭐라나?","JPN":"聖誕祭のために特別なデザートを作るから、ゼラチンが必要だとか。","ENG":"She said she wanted to make a special Christmas dessert and needed some gelatin powder.","TWN":"因為聖誕節要製作特別的甜點，好像需要吉利丁？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래서 우리 꼬맹이가 젤라틴 파우더를 넘겨줬다고 하던데…….","JPN":"それで、この子がゼラチンパウダーを渡したと聞いたのだが……","ENG":"So, one of my staff gave it to her, but...","TWN":"所以聽說我們家的小鬼把吉利丁粉交出去了……"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사실, 그게 조금 <color=#ffd34c>위험한</color> 물건이었거든.","JPN":"実は、それが少々<color=#ffd34c>危険な</color>ものなのだ。","ENG":"What she actually gave was something a bit more <color=#ffd34c>dangerous</color>.","TWN":"其實，那是有點<color=#ffd34c>危險的</color>物品。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"위험? 그건 어떤 어떤 종류의 위험이죠?","JPN":"危険？　それはどんな種類の危険なのですか？","ENG":"Dangerous? What kind of danger might that be?","TWN":"危險？那是哪種類型的危險？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>슬라임 파우더</color>야, 귀족 아가씨.","JPN":"<color=#ffd34c>スライムパウダー</color>よ、貴族のお嬢さん。","ENG":"It was <color=#ffd34c>slime powder</color>, Miss aristocrat.","TWN":"<color=#ffd34c>史萊姆粉末</color>呀，貴族小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"적당량 썼을 때는 독특한 식감을 줄 수 있지만, 까딱 양조절을 실패하면 큰일 나거든.","JPN":"適量を使うと独特な食感を出すことができるけど、量の調節に失敗すると大変なことになるの。","ENG":"It gives a unique texture when used in moderation, but if too much is used, it'll become a huge problem.","TWN":"適量使用時可以帶來獨特的口感，但一旦用量控制失敗就麻煩了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"어, 어떻게 되는데?","JPN":"ど、どうなるんだ？","ENG":"W-what's going to happen?","TWN":"會發生什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음, 말 그대로 반죽이 슬라임처럼 되어버린다고 해야 하나?","JPN":"うーん、その名のとおり生地がスライムのようになるっていうか。","ENG":"Mm... the dough will literally turn into a slime?","TWN":"嗯，應該說是麵團變得像史萊姆一樣了吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"원래의 형태로 돌아가기 위해, 자기 근처에 있는 모든 걸 빨아들여서 흡수해 버리지.","JPN":"元の形に戻るために、自分の周りにあるすべてを吸収してしまうわ。","ENG":"In order to return to its original form, it will start consuming everything around it.","TWN":"為了恢復原來的形態，會吸收附近所有的東西。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"잠깐, 원래의 형태라고?","JPN":"ちょっと待って、元の形だと？","ENG":"Wait, what do you mean by \\"original form?\\"","TWN":"等等，原來的形態嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그럼, 그 슬라임 파우더라는 것도 이면세계에서 구한 식재료란 말이야?","JPN":"じゃあ、そのスライムパウダーって物も裏世界で入手した食材なのか？","ENG":"Then, are you saying that the slime powder was also obtained from the Counterside?","TWN":"那麼，那種叫做史萊姆粉末的東西也是在異界獲得的食材嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어라? 이쪽 언니는 보기보다 제법인걸?","JPN":"あら？　こちらのお姉さんは見た目より賢そうね。","ENG":"Oh? That's a keen observation.","TWN":"咦？這位姊姊看起來比想像中厲害呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이면세계 식재료에 관해서는 관리국에서도 거의 연구가 진행되지 않은 걸로 알고 있는데?","JPN":"裏世界の食材については管理局でもあまり研究されていないと思うけど？","ENG":"I thought the Administration didn't conduct any research regarding food ingredients from the Counterside.","TWN":"關於異界食材的研究，管理局好像也沒做過多少吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아앗! 그건 말이지……!","JPN":"ああっ！　それは……！","ENG":"O-oh! Well...!","TWN":"啊！那個……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"어라? 아니지……?","JPN":"あれ？　待ってよ……","ENG":"Huh? This can be…","TWN":"呃？不對不對……？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"잘하면… 내가 저지른 걸 이 마녀 녀석들에게 전부 뒤집어 씌울 수도 있는 거잖아……?","JPN":"うまくいけば……私が犯したことをこの魔女のやつらに全部覆い被せられるじゃないか……？","ENG":"If I play my cards right... I just might be able to blame the witches for everything...?","TWN":"有可能……我可以把我犯下的所有罪行都推到這些魔女身上……？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후, 후후! 그래, 역시 나는 똑똑하다니깐?","JPN":"ふ、ふふ！　そうだよ、やっぱり私は天才だ。","ENG":"Heh heh heh! I knew I was so smart!","TWN":"呵呵呵！是吧，我果然很聰明吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……어, 어쨌든! 침식체가 발생할지도 모르는 식재료를 수녀님께 떠넘겼다는 소리야?","JPN":"……と、とにかく！　侵食体になるかもしれない食材をシスターに渡したのか？","ENG":"...A-anyway! Are you saying that you gave the Sister ingredients that could create a C.O.?","TWN":"……不管怎麼樣！你是說把可能會產生侵蝕體的食材給了修女嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그럼 큰일이잖아! 자영업자라면서 먹는 걸로 장난질해도 되는 거야?","JPN":"それは大変だ！　商売人なのに、食べ物でイタズラしたらダメだろう！","ENG":"This is bad! How can a cafe owner be so irresponsible by putting stuff like that into food?","TWN":"那可不得了！你不是開咖啡廳的嗎，怎麼能拿吃的開玩笑？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"죄, 죄송해요. 박사님…….","JPN":"す、すみません。教授……","ENG":"I-I'm sorry, Professor...","TWN":"對、對不起，教授……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저는 그냥 수녀님을 도와드리고 싶어서…….","JPN":"私はただシスターを助けたくて……","ENG":"I just wanted to help her out...","TWN":"我只是想幫修女的忙……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……적반하장도 유분수네요, 론 리 교수.","JPN":"……図々しいですわね、ローン・リー教授。","ENG":"...Talk about the pot calling the kettle black, Professor Lee.","TWN":"……真是賊喊捉賊啊，隆利教授。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적어도 당신은 그런 말을 할 자격이 없을 텐데요?","JPN":"少なくともあなたにそんなことを言う資格はないはずですわ。","ENG":"I believe you have no right to say that to others, no?","TWN":"至少你沒有資格說這種話吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐 당신……?","JPN":"ちょ、ちょっと、あなた……？","ENG":"W-wait, you–","TWN":"等、等一下，你……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 분명 이면세계에서 자란 솔로카오를 써서 침식체를 만든 전적이 있잖아요?","JPN":"あなたも確か裏世界で育ったソロカオを使って侵食体を作ったことがあるじゃないですか。","ENG":"You also have a track record of creating a C.O. using Solocao from the Counterside, do you not?","TWN":"你也曾用在異界中成長的獨株可可製造過侵蝕體吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"관리국의 수배령을 받은 것도 다 그것 때문 아니었나요?","JPN":"管理局から指名手配されたのもそのせいだったのでは？","ENG":"Is that not why you are a wanted criminal of the Administration?","TWN":"管理局的通緝令也是因為那個吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하, 하하……! 그건 다 옛날 이야기라고……!","JPN":"は、はは……！　それは全部昔のことなんだよ……！","ENG":"Ha, haha...! That's all in the past...!","TWN":"哈……哈哈……！那都是很久以前的事了……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"자, 잠깐 방금 솔로카오라고 하셨나요?","JPN":"ちょ、ちょっと！　今ソロカオって言いました？","ENG":"W-wait, did you say Solocao?","TWN":"等、等一下，你剛才說的是獨株可可嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐야, 그럼 당신이 만든 솔로카오 초콜릿에서 침식체가 나타날 수도 있다는 거야?","JPN":"なんだよ。じゃあ、君が作ったソロカオチョコレートから侵食体が現われるかもしれないってこと？","ENG":"Hold on. Then, a C.O. can appear because of the Solocao chocolate you made?","TWN":"什麼？那就是說你做的獨株可可巧克力裡也可能會出現侵蝕體？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"론 리 교수, 설마 당신 또 솔로카오 초콜릿을 만든 건가요?","JPN":"ローン・リー教授。あなた、まさかまたソロカオチョコレートを作ったのですか？","ENG":"Professor Lee, did you make Solocao chocolate again?","TWN":"隆利教授，難道你又做了獨株可可巧克力嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아, 아니! 그게 그러니까……!","JPN":"い、いや！　それはだから……！","ENG":"N-no! W-well...!","TWN":"不、那個，就是……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후, 후후……!","JPN":"ふ、ふふ……！","ENG":"Heh... Hehe...!","TWN":"呵、呵呵……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하아, 망했네. 이거…….","JPN":"はあ、ダメだ、これは……","ENG":"Ugh, I'm doomed...","TWN":"哈，完蛋了。這個……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……그럼, 상황을 정리해보죠.","JPN":"……では、状況を整理してみましょう。","ENG":"...Then, allow me to summarize the situation.","TWN":"……那麼，讓我們整理一下情況吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"넬슨 수녀님은 특별한 쇼콜라 무스 케이크를 만들기 위해 특별한 식재료를 썼습니다.","JPN":"シスター・ネルソンは特別なムースショコラを作るために、特別な食材を使用しました。","ENG":"Sister Nelson has used special ingredients to create a special chocolate mousse cake.","TWN":"尼爾森姊妹為了製作特別的巧克力慕斯蛋糕，使用了特別的食材。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 재료는 슬라임 파우더와 솔로카오 초콜릿.","JPN":"その材料はスライムパウダーとソロカオチョコレート。","ENG":"The ingredients she used include slime powder and Solocao chocolate.","TWN":"那些食材是史萊姆粉和獨株可可巧克力。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 두 재료는 평범한 재료가 아닌, 이면세계 식재료죠.","JPN":"この2つは普通の材料ではなく、裏世界の食材です。","ENG":"These two are no ordinary ingredients, but those from the Counterside.","TWN":"這兩種材料並不是普通的材料，而是異界食材。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이면세계 식재료는 저마다 특별한 효능을 가지고 있어.","JPN":"裏世界の食材はそれぞれ特別な効能を持っているわ。","ENG":"In the Counterside, each ingredient has its own special effect.","TWN":"異界食材各自都有特殊的功效。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 중에서는 병을 낫게 하거나, 기분을 좋게 만드는 효능을 가진 것도 있지만…….","JPN":"その中には病気を治癒したり、気分をよくしてくれる効能を持っているものもあるけど……","ENG":"Some can cure illnesses, and others can even make you feel good, but...","TWN":"其中有些能治病，也有些能讓人心情愉快……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"뭐든 과하면 독이 되는 법이거든.","JPN":"何でも過剰だと毒になるの。","ENG":"Anything in excess can be toxic.","TWN":"但凡事過猶不及。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이번 케이스처럼 전혀 다른 식재료가 섞이면, 어떤 작용이 발생할지 나도 예상할 수 없어.","JPN":"今回のケースのようにまったく異なる食材が混ざってしまうとどんな作用が発生するか、私も予想できないわ。","ENG":"In this case, we don't know what will happen as the two different ingredients mix.","TWN":"像這次的情況一樣，如果混入完全不同的食材，我也無法預料到後續會發生什麼反應。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"운이 좋다면 좋은 효과를 발휘할 수도 있지만, 그게 아니라면 아마도…….","JPN":"運が良ければいい効果を発揮するかもしれないけど、そうじゃなかったらたぶん……","ENG":"If we're lucky, the cake could have a positive effect, but if that's not the case, then...","TWN":"運氣好的話可能會發揮出不錯的效果，但如果不是的話，恐怕……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"죄송해요…….","JPN":"すみません……","ENG":"I'm sorry...","TWN":"非常抱歉……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"미안합니다… 잘못했습니다… 다시는 안 그러겠습니다…….","JPN":"ごめんなさい……私が悪いです……もう2度とやりません……","ENG":"I'm so sorry... I won't ever do it again...","TWN":"對不起……是我的錯……我再也不會這樣了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사과는 우리한테 할 게 아니라, 수녀님을 구해낸 뒤에 직접 하라고.","JPN":"妾たちにではなくて、シスターを助けた後に直接謝るように。","ENG":"Don't apologize to us. Apologize to Sister Nelson after we rescue her.","TWN":"道歉不是對我們說的，等救出修女後親自去道歉吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"죄송합니다. 제 불찰이었습니다, 아가씨.","JPN":"申し訳ございません。私の不始末です、お嬢様。","ENG":"My apologies, Lady Elizabeth. It was my mistake.","TWN":"對不起，是我的失誤，小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 제가 수녀님께 쇼콜라 무스 케이크 레시피를 알려드리지 않았다면, 이런 일은…….","JPN":"そもそも私がシスターにムースショコラのレシピを教えていなかったら、こんなことには……","ENG":"If I had not given her the recipe, all of this would not have happened...","TWN":"如果一開始我沒有告訴修女巧克力慕斯蛋糕的食譜，就不會發生這種事了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘못한 것도 없는데 쉽게 고개를 숙이지 마세요, 라이언.","JPN":"あなたの失敗ではないですから安易に頭を下げないように、ライアン。","ENG":"Do not admit fault when you did nothing wrong, Ryan.","TWN":"你沒有做錯什麼，不要輕易認錯，瑞安。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 자리에서 우리는 어디까지나 손님일 뿐입니다.","JPN":"この場では私たちはあくまでも客ですから。","ENG":"We are here as guests.","TWN":"我們到這再怎麼說都只是客人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"자, 어쨌든 대충 상황은 알아들었지?","JPN":"さて、とにかくだいたいの状況はわかっただろう？","ENG":"Now, you all get what's going down, right?","TWN":"那麼，情況大概了解了吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"지금, 이 문 뒤에는 이면세계 식재료가 뒤섞여 어떤 상황이 벌여져 있어도 이상하지 않아!","JPN":"今、この扉の向こうでは裏世界の食材が混ざり合って、どんな状況が起こっていてもおかしくない！","ENG":"With the ingredients from the Counterside all mixed together behind this door, anything can happen!","TWN":"現在，這扇門後面異界的食材混入其中，不管發生什麼情況都不奇怪！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러니까 다들 긴장의 끈을 놓지 말고 마음 단단히 먹으라고!","JPN":"だから、みんな油断しないように！","ENG":"So, stay alert and brace yourselves!","TWN":"所以大家千萬不要放鬆警惕！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"다들 전투 준비……!","JPN":"みんな、戦闘準備……！","ENG":"Everyone prepare for combat...!","TWN":"所有人準備戰鬥……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오호호호호호~! 메리~ 크리스마스……!","JPN":"オホホホホホ～！　メリー～クリスマス……！","ENG":"Hohohohoho! Merry! Christmas...!","TWN":"喔呵呵呵呵～！聖誕～快樂……！"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"아, 아하하… 여, 여러분 메리 크리스마스예요…….","JPN":"あ、あはは……み、みなさん。メリークリスマスです……","ENG":"A-ah hah hah... M-merry Christmas, everyone...","TWN":"啊、啊哈哈……大，大家聖誕快樂……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"아무것도 보이지 않아요…….","JPN":"何も見えません……","ENG":"I cannot see a thing...","TWN":"什麼都看不見……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"그, 그렇지만… 보이지 않아서 더 치욕스럽다고요……!","JPN":"で、ですが……見えないからもっと恥ずかしい……！","ENG":"B-but... it is all the more humiliating because I cannot...!","TWN":"但、但是……看不見反而更丟臉啊……！"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오호호호호~! 특별한 크리스마스를 위해, 특별한 준비를 하고 있었다네!","JPN":"オホホホホ～！　特別なクリスマスのために、特別な準備をしていたのだぞ！","ENG":"Hohohoho! I've prepared a special gift for a special Christmas!","TWN":"喔呵呵呵呵～！為了特別的聖誕節，我做了特別的準備！"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L34_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"그러니 반항하지 말고 얌전히 이 산타복을 입게나, 시스터.","JPN":"だから反抗しないで、大人しくこのサンタの衣装を着るのだ、シスター。","ENG":"So, do not resist and put on the Santa suit, Sister.","TWN":"所以不要反抗，乖乖穿上這件聖誕裝吧，修女。"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄송해요… 루체 자매님… 그렇지만 벌써 손님들이…….","JPN":"すみません……シスター・ルーチェ……でも、もうお客さんが……","ENG":"I'm sorry... Sister Luce... But our guests are already here...","TWN":"抱歉……露契姊妹……可是客人們已經……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"그, 그럼… 차라리 불이라도 꺼주세요… 제발…….","JPN":"で、では……せめて明かりでも消してください……お願い……","ENG":"Th-then... at least... turn off the lights... Please...","TWN":"那、那就……索性請把燈關了吧……拜託了……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"시키는 대로… 할 테니까…….","JPN":"言われたとおりに……するから……","ENG":"Then I'll do... as you say...","TWN":"讓我幹什麼……都可以……"},"stage":{"bg":"CHOCOLAT_01","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……유나, 잉그리드.","JPN":"……ユナ、イングリッド。","ENG":"...Yuna, Ingrid.","TWN":"……尤娜，英格麗。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"좋은 말할 때 눈 감지 그래? 저건 애들이 볼만한 시츄에이션이 아니라고?","JPN":"目を閉じろ。あれは子どもたちが見るようなシチュエーションではない。","ENG":"I suggest you both cover your eyes. This isn't something that's meant for children to see.","TWN":"趕緊把眼睛閉上！這可不是小孩子能看的場面啊！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};